import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface ExerciseVolume {
  exercise: string;
  volume: number;
}

interface FitnessData {
  summary: {
    exercisesCompleted: number;
    totalVolume: string;
    muscleGroups: string[];
  };
  exerciseVolume: ExerciseVolume[];
}

export default function Widget() {
  const { summary, exerciseVolume } = response.data as FitnessData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#F59E0B', mb: 1 }}>
              Workout Summary
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Exercises Completed: {summary.exercisesCompleted}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Total Volume: {summary.totalVolume}
            </Typography>
            <Stack direction="row" spacing={0.5} sx={{ mt: 0.5 }}>
              {summary.muscleGroups.map((muscle, index) => (
                <Typography key={index} variant="caption" sx={{ color: '#9CA3AF', fontSize: '11px' }}>
                  {muscle}
                </Typography>
              ))}
            </Stack>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: exerciseVolume.map((ev) => ev.volume),
                color: '#F59E0B',
              },
            ]}
            xAxis={[
              {
                data: exerciseVolume.map((ev) => ev.exercise),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 10,
                  fill: '#9CA3AF',
                },
              },
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
